var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교관님! 낙오됐던 친구들은 전부 구조했습니다!","JPN":"教官！　はぐれたメンバーは全員救助しました！","ENG":"Sir! We've secured all the stragglers!","TWN":"教官！脫隊人都救回來了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잘했다, 폭탄은?","JPN":"よくやった、爆弾は？","ENG":"Good. How are we doing with firepower?","TWN":"非常好，那炸彈呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"바, 방금 전에 던진 수류탄이 마지막이었습니다! 이제 더는 없어요!","JPN":"さ、さっき投げた手榴弾が最後でした！　もうありません！","ENG":"W-we just tossed our last grenade! We're all out of explosives!","TWN":"剛剛扔出去的手榴彈是最後一顆，都沒有了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"어쩌죠? 저것들 우리를 붙잡으면 갈기갈기 찢을 기세던데……!","JPN":"どうしましょう？　切り裂くような勢いで追撃してきます……！","ENG":"What should we do? They're going to tear us to pieces if they catch up to us…","TWN":"怎麼辦？感覺那些人抓到我們後，會把我們生吞活剝……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……기다려. 지금 생각 중이다.","JPN":"……待ってくれ。今考え中だ。","ENG":"…Give me a minute. I'm trying to think.","TWN":"……先不要急，我正在想辦法。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"어리석은 것들. 우리 형제들에게서 벗어날 수 있을 줄 알았느냐?","JPN":"愚か者め。我が兄弟の手から逃れられると思ったのか？","ENG":"Fools. Did you really think you could escape us?","TWN":"愚蠢的傢伙，以為可以逃出我們弟兄的五指山嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"포기해라. 계속 저항한다면 차라리 죽여 달라고 빌게 해 주지.","JPN":"諦めろ。抵抗し続けるならいっそ殺してくれと懇願するまで痛めつけてやる。","ENG":"Yield. If you continue to resist, we'll make you wish you were dead.","TWN":"放棄吧！再繼續抵抗的話，我會讓你們生不如死！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……주교 엘카노. 본명 로버트 리.","JPN":"……司教エルカノ。本名ロバート・リー。","ENG":"…Bishop Elcano. Real name, Robert Lee.","TWN":"……主教 埃爾卡諾，本名 羅伯特·李。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"음? 내 이름을 어떻게……?","JPN":"うむ？　私の名前をどうして……？","ENG":"Huh? How did you know my name?","TWN":"嗯？你怎麼知道我的名字…？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다단계 사기를 저지르고 국외 도피했다가 예언회에 투신했던 쓰레기, 맞나?","JPN":"ネズミ講詐欺を犯して国外逃亡し、預言会に潜んだクズ、で合ってるか？","ENG":"A scumbag who fled overseas after a failed pyramid scheme, only to take refuge with the MPS. That sound about right?","TWN":"犯下多個詐騙案逃往海外後，加入預言會的垃圾，我沒說錯吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이, 이 거지 주제에 내 뒷조사를 했다고?!","JPN":"お、お前、乞食のくせに私のことを探ったな！？","ENG":"Y-you dared dig up my history, you vagrant?!","TWN":"你…竟敢私下調查我？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그래, 그래서 그게 어쨌다는 거지!","JPN":"ああ、それがどうした？","ENG":"So what?","TWN":"沒錯，你說的沒錯又怎樣？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너한테 속은 사람들이 얼마나 고통스럽게 하루하루를 보냈을지, 잠시라도 생각해 본 적 있나?","JPN":"貴様に騙されてどれほど多くの人々がどれだけ苦しんだのか、考えたことはあるのか？","ENG":"Have you ever thought about how many innocent people suffered because of your scheme?","TWN":"你有一時片刻想過，那些被你騙的人每天過得有多痛苦嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"……하. 무슨 소리를 하나 했더니.","JPN":"……はっ。　何を言い出すかと思ったら。","ENG":"Ha… So that's what you wanted to talk about?","TWN":"……哈，我還以為你要說什麼。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그들이 바친 돈은 예언을 이루는 데 쓰였다! 이만큼 값진 투자가 어디 있단 말이냐!","JPN":"奴らが貢いだ金は預言を成し遂げるのに使われた！　こんな貴重な投資は他にないだろうが！","ENG":"Their offerings were well spent on making the prophecy come true! What better investment is there?","TWN":"他們奉獻的錢是用來實現預言的！有比這更划算的投資嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"겁에 질려서 얼굴도 못 내미는 놈이 건방지게! 네놈은 특별히 내 손으로 처단해 주마!","JPN":"怖がって顔も出せない奴が生意気に！　お前は特別に私の手で断罪してやろう！","ENG":"You dare judge me? You're nothing but a coward who won't even show your face! I'll make a special exception, and take you out myself!","TWN":"因為害怕而不敢露臉的傢伙，還敢給我說什麼大道理！我就特別親手處決你吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 예언회에서 한 자리 차지하는 데 썼겠지. 그것도 투자라면 투자겠군.","JPN":"あんたが預言会でのし上がるために使ったんだろう。それも投資というなら投資だろうな。","ENG":"I bet you used that money to bribe your way to the top within the MPS. Then again, I guess you really could call that an investment of sorts.","TWN":"那些錢應該也有用來幫助你，在預言會取得一席之地吧？那也算投資吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교관님, 저 자를 자극해서 어떻게 하시려는 겁니까?","JPN":"教官、そんなに煽ってどうするつもりですか？","ENG":"Sir, why are you deliberately provoking him?","TWN":"教官，你一直刺激他是想做什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"시간끌기. 카운터한테 한 방 먹이려면 개인화기로는 부족해.","JPN":"時間稼ぎだ。カウンターに一発喰らわすには小火器では足りない。","ENG":"I'm buying us time. Small arms won't be enough to take out a Counter.","TWN":"拖延時間。要給制裁者一擊的話，光靠個人武器是不夠的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"좋아. 다 됐군. ","JPN":"よし、できた。","ENG":"Good. It's ready now. ","TWN":"OK，做好了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"급조한 폭발물이지만 화력은 쓸 만할 거다. 이걸로…….","JPN":"急造した爆発物だが、火力は悪くないはずだ。これで……","ENG":"It's just an IED, but it should pack enough of a punch. Now, I'll take this and…","TWN":"雖然是匆忙製作的炸彈，但火力應該還可以。就用這個……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":" 응?","JPN":"うん？","ENG":" Huh?","TWN":" 嗯？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"어……?","JPN":"あれ……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주교님, 하늘이 어두워졌습니다!","JPN":"司教様、空が暗くなりました！","ENG":"The sky has grown dark, Your Holiness!","TWN":"主教，天好像變暗了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"오오! 보이느냐! 너희들을 심판하라는 예언자님의 뜻이 틀림없다!","JPN":"おお！　見えるか！　貴様らを断罪せよという預言者様の意思に違いない！","ENG":"Ooh! Lo and behold! It must be a sign from the Prophet that retribution is upon you!","TWN":"呵呵！看到沒有！肯定就是預言家要審判你們的意思！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"그런데 저희 쪽으로 날아오는 저거…… 트럭 아닙니까?","JPN":"ところで私たちの方に飛んでくるあれは……トラックですかね？","ENG":"But there's something flying at us… is that a truck?","TWN":"不過朝我們飛過來的……是卡車嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"…What?","TWN":"……什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아악!","JPN":"うわああっ！","ENG":"Aaaah!","TWN":"呃啊啊啊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"에, 엘카노 주교님이 트럭에 깔리셨다! 이럴 땐 어떻게 해야 하지?!","JPN":"エ、エルカノ司教様がトラックの下敷きに！　こういう時はどうすればいいんだ？","ENG":"B-Bishop Elcano has been squashed by a truck! What are we to do?!","TWN":"埃…埃爾卡諾主教被壓在車底，這時候該怎麼辦？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"차, 찬송가! 찬송가를 부르자! 우리 노래를 들은 주교님께서 트럭을 박차고 나오실 거다!","JPN":"さ、賛美歌！　賛美歌を歌おう！　私たちの歌を聞いた司教様がトラックを吹き飛ばして出てくるはずだ！","ENG":"H-hymns! Let us sing a hymn! I'm sure the Bishop will kick that truck right off when he hears our singing!","TWN":"唱…唱詩歌！來唱詩歌吧！主教聽到我們的詩歌後，一定可以自己脫困的！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교, 교관님……! 방금 보셨습니까? 트럭이 저 카운터 놈을 덮쳐 버렸어요!","JPN":"きょ、教官……！　今の見ましたか？　あのカウンターのやつがトラックの下敷きになりました！","ENG":"S-sir! Did you just see that? A truck landed on that Counter scumbag!","TWN":"教…教官…！你剛才有看到嗎? 卡車直接撞向那個制裁者欸！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 저렇게 적극적으로 달려들다니 첫눈에 반했나 보군.","JPN":"ああ、あんなに積極的に飛びつくなんて、一目惚れしたようだな。","ENG":"Yeah, I saw. The truck must've fallen in love at first sight, leaping at him like that.","TWN":"有看到，那麼積極地撲上去，看來是一見鍾情。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리에게는 기회다. 수습한 친구들을 모두 차에다 실어.","JPN":"俺たちにとっては見逃せないチャンスだ。仲間を全員車に乗せろ。","ENG":"This is our chance. Load all the stragglers on the vehicles.","TWN":"好機會，趁現在趕快將大家載上車。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교관님은 안 타십니까?","JPN":"教官は乗らないんですか？","ENG":"Aren't you going to hop on, sir?","TWN":"教官你不搭嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"엘카노 주교가 죽었는지 확인해야 한다. 살려 보내면 또 무슨 짓을 저지를지 모를 놈이야.","JPN":"エルカノ司教が死んだのか確認しなければ。生かしておくと何をしでかすかわからない奴だからな。","ENG":"I have to check if Elcano's really dead. There's no telling what he'd do next if he survives.","TWN":"當然要確認那個埃爾卡諾主教死了沒有。萬一沒死，不知道他又會做出什麼事來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 여유 부릴 시간 없습니다. 휴먼.","JPN":"そんな余裕を見せる時間はありません、ヒューマン。","ENG":"You don't have such luxury of time, human.","TWN":"現在沒那個美國時間，人類。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"호라이즌? 언제 장갑차에서 내렸던 거야?","JPN":"ホライズン？　いつ装甲車から降りたんだ？","ENG":"Horizon? When did you get out of the APC?","TWN":"地平線？你是什麼時候下裝甲車的？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설명해 봐, 무슨 이유에서 막는 거냐?","JPN":"説明してみろ。なぜ止めるんだ？","ENG":"Tell me. Why are you trying to stop me?","TWN":"你解釋一下，為什麼要攔我？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"예언회 신도들은 한 명도 휘말리지 않았습니다. 지금 접근하면 난전이 벌어질 겁니다.","JPN":"預言会の信徒たちは一人も巻き込まれていません。今接近したら乱戦になるでしょう。","ENG":"None of the other followers of the Society have been neutralized. If you approach the truck now, a chaotic battle would be inevitable.","TWN":"預言會的信徒們都不在車底。 現在靠近他的話，恐怕會生亂。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추가로 방금 전 굉음을 들은 침식체들이 이곳으로 몰려들고 있군요.","JPN":"さらに、先ほどの轟音を聞いた侵食体がこちらに押し寄せてきています。","ENG":"Furthermore, the C.O.s that heard the explosion are on their way here.","TWN":"另外，剛剛聽到聲響的侵蝕體正朝這裡聚集中。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"불필요한 교전을 야기해 사상자를 발생시킬 작정이라면 말리지 않겠습니다만.","JPN":"不要な交戦を引き起こして死傷者を出すつもりなら止めませんが。","ENG":"I won't stop you if you'd rather begin an unnecessary engagement and deal with mass casualties.","TWN":"如果你是想打算開戰造成傷亡的話，那我就不攔你了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니, 이번엔 네 말이 옳다. 아쉽지만 다음을 기약할 수밖에.","JPN":"いや、今回はあんたが正しい。残念だが、次の機会を窺うしかない。","ENG":"No, you're right this time. It's too bad, but I'll just have to wait for another chance.","TWN":"不，這次你說的對。 雖然有點可惜，但也只能下次了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다들 시동 건다! 주거 구역까지 있는 힘껏 밟아!","JPN":"エンジンをかけろ！　住居区域まで突っ走れ！","ENG":"Start your engines! Step on it until we reach the residential area!","TWN":"大家發動！ 全力開往住宅區！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"크허……! 허억……! 헉……!","JPN":"ぐはっ……はあっ、はっ……！","ENG":"Ack… Hngh…! Gah…!","TWN":"咳咳…！咳咳…！咳…！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"젠장…… 카운터가 숨어 있었나…….","JPN":"クソ……カウンターが隠れていたのか……！","ENG":"Damn it… A Counter must have been hiding in their midst…","TWN":"該死……難道當中有制裁者……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"으윽, 팔까지 부러졌잖아…….","JPN":"ううっ、腕が折れてしまったじゃないか……","ENG":"Ugh, I think I broke my arm too…","TWN":"凹嗚，我的手臂都斷了……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"아무도 없나! 있으면 대답해! 주교인 내가 여기 쓰러져 있단 말이다!","JPN":"誰かいないか！　いるなら答えろ！　司教様の私がここに倒れているのだ！","ENG":"Is anyone there?! Answer me! Your Bishop lies wounded here!","TWN":"有人嗎！回答我！主教就在這裡！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그래! 어서 나를 부축해라! 어서!","JPN":"ああ、早く私を助けろ！　早く！","ENG":"That's it! Help me up at once! Hurry!","TWN":"很好！快扶我起來！快點！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"제프티 놈들에게 강화복을 받아내야겠어…… 그거라면 카운터라도……","JPN":"ジェフティのやつらから強化服をもらわないと……それならカウンターでも……","ENG":"I'll get one of those power suits from Jehuty… Even a Counter couldn't withstand such a-","TWN":"我要跟傑夫堤的傢伙討一套強化服來穿才行……這樣就算是制裁者……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 줄 사람은 생각도 안 하는데 벌써부터 배가 불렀네.","JPN":"フフッ。支給する側はそんなこと考えてもいないのに、そんな贅沢な夢を見ていいのかしら？","ENG":"Heh. What makes you think we'll give it to you?","TWN":"呵呵。也不想想自己做了什麼事，還有臉說這種話？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하청업자 주제에 선을 넘은 거 아닐까?","JPN":"下請けの分際で一線を越えたと思わない？","ENG":"Aren't you getting a little ahead of yourself? You're just a subcontractor.","TWN":"身為承包商，你是不是有點越界啦？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"다, 당신은…… 제프티의……?","JPN":"あ、あなたは……ジェフティの……？","ENG":"Y-you… You're that lady from Jehuty…","TWN":"你…你是…傑夫堤的…？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"오, 오해입니다. 전부 오해예요. 당신들을 배신할 생각은 털끝만큼도 없었습니다!","JPN":"ご、誤解です。全部誤解です。あなた方を裏切るつもりは微塵もございませんでした！","ENG":"P-please… It's all just a misunderstanding. I wouldn't dare dream of betraying you!","TWN":"誤…這是誤會，誤會一場。我完全沒有要背叛你們的想法！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"방금 그 얘기는, 부상 때문에 저도 모르게 내뱉었던 헛소리라고 생각해 주시고……","JPN":"さっきのあの話は、怪我のせいで思わず吐き出したうわごとだと思ってくだされば……","ENG":"What you heard earlier… that was just me rambling deliriously from my injury, I assure-","TWN":"剛才是因為我受傷腦袋不清楚，才會說那種話，請你不要介意……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"케헥……! 컥……!","JPN":"ぐはっ……！　げっ……！","ENG":"Ack…! Ack...!","TWN":"咳咳……！呃……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_SMALL"},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아. 왜 항상 변명하는 레퍼토리는 다들 서로 비슷비슷할까. 표절한 것도 아닐 텐데.","JPN":"はぁ。なぜみんな言い訳のレパートリーが似たり寄ったりなのかしら？　盗用してるわけでもないのに。","ENG":"Ugh… Why do they all try to make the same lame excuses? It's not like they can plagiarize that sort of thing.","TWN":"哈，為什麼辯解的台詞都差不多呢？應該不是抄襲的吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"잘 들어. 방금 내가 네 목에 예쁜 구멍을 하나 뚫어 줬어. 남아 있던 네 부하들처럼.","JPN":"よく聞きなさい。今、私が君の首にきれいな穴を一つ開けてあげたの。残っていた君の部下たちと同じようにね。","ENG":"Listen closely. I just poked a lovely little hole in your neck. Just like the rest of your followers. Well, the ones still left anyway.","TWN":"聽好了。我剛才在你脖子上開了一個漂亮的洞，就和你其他的手下一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"공기가 새서 말은 하기 어렵겠지만, 카운터니까 손으로 꼭 막고 있으면 병원에 도착할 때까진 안 죽을 거야.","JPN":"空気が漏れて話すのが難しいだろうけど、\\nあなたはカウンターなんだから手でギュッと抑えておけば、病院に到着するまでは死なないわ。","ENG":"You won't be able to talk because their air will leak right through, but you'll make it to the hospital alive if you squeeze it tight… being a Counter and all.","TWN":"雖然會因為漏氣不好說話，但你是制裁者嘛～用手堵住洞的話，在抵達醫院前應該都不會死。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자아, 그러니까 뛰어. 어서.","JPN":"さあ、だから走って。はやく。","ENG":"So you'd better start running. Now.","TWN":"快啊，快跑起來，快跑！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 필사적인 모습으로 내게 영감을 불어넣어 줘.","JPN":"君の必死な姿で私にインスピレーションを吹き込んでほしいの。","ENG":"Inspire me with your desperation.","TWN":"用你拼命奔跑的樣子替我增添靈感！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"켁……! 케헤……! 헤엑……!","JPN":"げっ……！　げぇ……！　がはっ……！","ENG":"Ack…! Hack…! Hngh…!","TWN":"咳……！咳……！嗚……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아, 그런데 이를 어쩌니. 내 생각보다 피 냄새가 너무 고약하네.","JPN":"はぁ、でもどうしよう。思ったより血の臭いがひどすぎるわね。","ENG":"Oh, but this won't do at all. The stench of your blood is more pungent than I expected.","TWN":"哎呀～可是怎麼辦呢？血的味道比我想像中還難聞。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"잘 자던 애들까지 전부 깨워 버리겠다. 그치?","JPN":"寝ていた子どもたちまで起こしてしまうわ。そう思わない？","ENG":"You just might wake up all those critters out there. Wouldn't you agree?","TWN":"只好把沉睡中的孩子都叫醒囉？你說對嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};